mapper.select:
SELECT l.lot_id, l.project_id, p.project_name, l.lot_code, l.lot_name, l.lot_no, l.lot_scope, l.status, l.budget_amount, l.bid_start_time, l.bid_end_time, l.opening_time, l.evaluation_mode, l.award_mode, l.remark, l.version, l.create_time, l.update_time FROM t_bid_lot l INNER JOIN t_bid_project p ON p.project_id = l.project_id
l.deleted_flag = #{queryForm.deletedFlag} AND p.deleted_flag = 0
AND ( l.lot_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND l.project_id = #{queryForm.projectId}
AND l.status = #{queryForm.status}
ORDER BY l.project_id DESC, l.lot_no ASC, l.lot_id DESC
